SELECT P.title, M.views, M.downloads, M.citations
FROM publications P
LEFT JOIN metrics M ON P.pub_id = M.pub_id;

SELECT pub_id, COUNT(coi_id) AS conflict_count
FROM conflicts_of_interest
GROUP BY pub_id;

SELECT 'authors' AS user_type, COUNT(*) AS count FROM authors
UNION ALL
SELECT 'reviewers', COUNT(*) FROM reviewers;

SELECT authors.name, authors.email
FROM authors
INNER JOIN conflicts_of_interest ON authors.author_id = conflicts_of_interest.user_id;

SELECT a.name, a.affiliation, c.publication_id
FROM authors a
INNER JOIN collaborations c ON a.author_id = c.author_id;

SELECT title, doi
FROM publications
WHERE journal_name = 'Journal of Marine Biology' AND status = 'Published';

SELECT publications.title, languages.language_name, languages.code
FROM publications
INNER JOIN languages ON publications.language_id = languages.language_id;
